def solve(*args):
    if len(args) < 2:
        return "Error: At least two arguments are required."

    try:
        scores = list(map(int, args))
    except ValueError:
        return "Error: All arguments must be integers."

    if any(score < 0 for score in scores):
        return "Error: Scores must be non-negative."

    total_score = sum(scores)
    average_score = total_score / len(scores)

    return {
        "total": total_score,
        "average": average_score
    }
